void clear_allocation(allocation *a)
{
	if (a) {

		if(a->is_valid)
			turn_report_allocation_delete(a);

		if(a->tcs.elems) {
			size_t i;
			size_t sz = a->tcs.sz;
			for(i=0;i<sz;++i) {
				tcp_connection *tc = a->tcs.elems[i];
				if(tc) {
					delete_tcp_connection(tc);
					a->tcs.elems[i] = NULL;
				}
			}
